INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 24, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 2, 0.0, 10046, "アヤネ", 0.0, "2030/12/17 14:59:59", 401, "2020/07/31 12:00:00", 24001, 0.0, 102301);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 2, 2.21, 10046, "アヤネ", 0.0, "2030/12/17 14:59:59", 402, "2020/07/31 12:00:00", 24002, 0.0, 102301);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 24, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 2, 0.0, 10046, "アヤネ", 0.0, "2030/12/17 14:59:59", 403, "2020/07/31 12:00:00", 24003, 0.0, 102301);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 24, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 1, 1.99, 10046, "アサヒ", 0.0, "2030/12/17 14:59:59", 701, "2020/07/31 12:00:00", 24004, 0.0, 192201);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 2, 2.21, 10046, "アサヒ", 0.0, "2030/12/17 14:59:59", 702, "2020/07/31 12:00:00", 24005, 0.0, 192201);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 24, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 1, 3.33, 10046, "アサヒ", 0.0, "2030/12/17 14:59:59", 703, "2020/07/31 12:00:00", 24006, 0.0, 192201);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 24, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 2, 0.0, 10046, "部員３", 0.0, "2030/12/17 14:59:59", 801, "2020/07/31 12:00:00", 24007, 0.0, 192301);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 2, 2.68, 10046, "部員３", 0.0, "2030/12/17 14:59:59", 802, "2020/07/31 12:00:00", 24008, 0.0, 192301);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 24, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 2, 0.0, 10046, "部員３", 0.0, "2030/12/17 14:59:59", 803, "2020/07/31 12:00:00", 24009, 0.0, 192301);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "やった！", 1, 0.0, 10046, "", 0.0, "2030/12/17 14:59:59", 501, "2020/07/31 12:00:00", 24010, 0.0, 192501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "勝ったよ！", 1, 0.0, 10046, "", 0.0, "2030/12/17 14:59:59", 502, "2020/07/31 12:00:00", 24011, 0.0, 192501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "いい調子！", 1, 0.0, 10046, "", 0.0, "2030/12/17 14:59:59", 503, "2020/07/31 12:00:00", 24012, 0.0, 192501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (6, 24, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 2, 5.33, 10046, "ミサト", 0.0, "2030/12/17 14:59:59", 111, "2020/07/31 12:00:00", 24013, 0.0, 113501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 2, 6.85, 10046, "ミサト", 0.0, "2030/12/17 14:59:59", 112, "2020/07/31 12:00:00", 24014, 0.0, 113501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 2, 3.0, 10046, "ミサト", 0.0, "2030/12/17 14:59:59", 113, "2020/07/31 12:00:00", 24015, 0.0, 113501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 2, 6.11, 10046, "ダイチ", 0.0, "2030/12/17 14:59:59", 611, "2020/07/31 12:00:00", 24016, 0.0, 192401);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 2, 6.75, 10046, "ダイチ", 0.0, "2030/12/17 14:59:59", 612, "2020/07/31 12:00:00", 24017, 0.0, 192401);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 24, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 2, 0.0, 10046, "ダイチ", 0.0, "2030/12/17 14:59:59", 613, "2020/07/31 12:00:00", 24018, 0.0, 192401);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 24, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 1, 4.52, 10046, "ハツネ", 0.0, "2030/12/17 14:59:59", 211, "2020/07/31 12:00:00", 24019, 0.0, 113401);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 24, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 1, 3.89, 10046, "ハツネ", 0.0, "2030/12/17 14:59:59", 212, "2020/07/31 12:00:00", 24020, 0.0, 113401);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 2, 13.49, 10046, "ハツネ", 0.0, "2030/12/17 14:59:59", 213, "2020/07/31 12:00:00", 24021, 0.0, 113401);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 2, 3.17, 10046, "カヤ", 0.0, "2030/12/17 14:59:59", 311, "2020/07/31 12:00:00", 24022, 0.0, 106501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 2, 4.42, 10046, "カヤ", 0.0, "2030/12/17 14:59:59", 312, "2020/07/31 12:00:00", 24023, 0.0, 106501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (6, 24, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 1, 2.89, 10046, "カヤ", 0.0, "2030/12/17 14:59:59", 313, "2020/07/31 12:00:00", 24024, 0.0, 106501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (4, 24, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 3, 3.71, 10046, "アヤネ", 0.0, "2030/12/17 14:59:59", 421, "2020/07/31 12:00:00", 24025, 0.0, 102301);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 24, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 1, 5.1, 10046, "アサヒ", 0.0, "2030/12/17 14:59:59", 721, "2020/07/31 12:00:00", 24026, 0.0, 192201);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 3, 4.34, 10046, "部員３", 0.0, "2030/12/17 14:59:59", 821, "2020/07/31 12:00:00", 24027, 0.0, 192301);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "いい勝負だったよ\nまたやろうね", 1, 0.0, 10046, "", 0.0, "2030/12/17 14:59:59", 521, "2020/07/31 12:00:00", 24028, 0.0, 192501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 2, 5.62, 10046, "ミサト", 0.0, "2030/12/17 14:59:59", 101, "2020/07/31 12:00:00", 24029, -360.0, 113501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 2, 9.58, 10046, "ミサト", 0.0, "2030/12/17 14:59:59", 102, "2020/07/31 12:00:00", 24030, -360.0, 113501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 24, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 2, 0.0, 10046, "ミサト", 0.0, "2030/12/17 14:59:59", 103, "2020/07/31 12:00:00", 24031, -360.0, 113501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 24, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 1, 9.13, 10046, "ミサト", 0.0, "2030/12/17 14:59:59", 104, "2020/07/31 12:00:00", 24032, -360.0, 113501);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 24, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 2, 8.27, 10046, "ミサト", 0.0, "2030/12/17 14:59:59", 105, "2020/07/31 12:00:00", 24033, -360.0, 113501);
